generated_oml:
// Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor located in motor controller, measuring electrical current and streaming data via MQTT"
    DTDFVocab:producedData CurrentDataTransmitted
]

instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder measuring angular position of the permanent magnet synchronous motor"
    DTDFVocab:producedData MotorAngleDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder behind the gearbox measuring angular position"
    DTDFVocab:producedData GearboxAngleDataTransmitted
]

instance DerivedTorqueSignal : DTDFVocab:SensingComponent [
    base:desc "Derived torque signal computed from motor and gearbox data, streamed via MQTT"
    DTDFVocab:producedData TorqueDataTransmitted
]

instance DerivedAngularVelocitySignal : DTDFVocab:SensingComponent [
    base:desc "Derived angular velocity signal computed from angular position data, streamed via MQTT"
    DTDFVocab:producedData AngularVelocityDataTransmitted
]

// Physical-to-virtual interaction: Data transmitted
instance CurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance TorqueDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom DerivedTorqueSignal
]

instance AngularVelocityDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom DerivedAngularVelocitySignal
]

// Data instances
instance CurrentData : DTDFVocab:Data [
    base:desc "Current data trace captured from CurrentDataTransmitted"
    DTDFVocab:fromData CurrentDataTransmitted
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Motor angle data trace captured from MotorAngleDataTransmitted"
    DTDFVocab:fromData MotorAngleDataTransmitted
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Gearbox angle data trace captured from GearboxAngleDataTransmitted"
    DTDFVocab:fromData GearboxAngleDataTransmitted
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Torque data trace captured from TorqueDataTransmitted"
    DTDFVocab:fromData TorqueDataTransmitted
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity data trace captured from AngularVelocityDataTransmitted"
    DTDFVocab:fromData AngularVelocityDataTransmitted
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

// Models
instance EngineeringComponentConnectorModel : DTDFVocab:Model [
    base:desc "SysML component–connector model of the motor and gearboxes"
    DTDFVocab:inputTo SysMLUDLEnabler
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "Simulink executable model of the permanent magnet synchronous motor"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance SimulinkGearwheelModel : DTDFVocab:Model [
    base:desc "Simulink executable model of the gearwheel gearbox"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink executable model of the cycloidal gearbox"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Coulomb‑Viscous friction sub‑model used within the Simulink gearbox blocks"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Stribeck friction sub‑model used within the Simulink gearbox blocks"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Dahl friction sub‑model used within the Simulink gearbox blocks"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "LuGre friction sub‑model used within the Simulink gearbox blocks"
    DTDFVocab:inputTo SimulinkMATLABEnabler
]

instance AnalyticalTorquePredictionModel : DTDFVocab:Model [
    base:desc "Analytical torque prediction model exported from simulation"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

// Data traces
instance CurrentDataTrace : DTDFVocab:Data [
    base:desc "Trace of motor current data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance MotorTorqueDataTrace : DTDFVocab:Data [
    base:desc "Trace of motor torque data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance MotorVelocityDataTrace : DTDFVocab:Data [
    base:desc "Trace of motor angular velocity data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance GearboxTorqueDataTrace : DTDFVocab:Data [
    base:desc "Trace of gearbox torque data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance GearboxVelocityDataTrace : DTDFVocab:Data [
    base:desc "Trace of gearbox velocity data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance SystemTorqueDataTrace : DTDFVocab:Data [
    base:desc "Trace of overall system torque data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

instance SystemVelocityDataTrace : DTDFVocab:Data [
    base:desc "Trace of overall system velocity data"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

// Aggregated data
instance AggregatedFrictionParametersData : DTDFVocab:Data [
    base:desc "Aggregated friction model parameters derived from continuous estimation"
    DTDFVocab:inputTo DataProcessingComponentEnabler
]

// Enablers
instance SysMLUDLEnabler : DTDFVocab:Enabler [
    base:desc "SysML UDL modeling enabler for engineering component and connector model"
    DTDFVocab:enables SimulationService
]

instance SimulinkMATLABEnabler : DTDFVocab:Enabler [
    base:desc "Simulink MATLAB enabler for running simulation models"
    DTDFVocab:enables SimulationService, FrictionEstimationService, ComparativeAnalysisService
]

instance DataProcessingComponentEnabler : DTDFVocab:Enabler [
    base:desc "Processing component that consumes data traces and produces aggregated outputs"
    DTDFVocab:enables DataAggregationService, FrictionEstimationService, ComparativeAnalysisService
]

instance DashboardVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard visualization enabler for real‑time monitoring"
    DTDFVocab:enables DashboardService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell enabler providing structural description of the robot axis"
    DTDFVocab:enables SimulationService
]

// Services
instance SimulationService : DTDFVocab:Service [
    base:desc "Simulates motor and gearbox behavior in Simulink"
    DTDFVocab:provides SimulationResultsInsight
]

instance FrictionEstimationService : DTDFVocab:Service [
    base:desc "Continuous friction model identification and parameter estimation using white‑box and black‑box approaches"
    DTDFVocab:provides FrictionParameterUpdatedInsight
]

instance DataAggregationService : DTDFVocab:Service [
    base:desc "Aggregates and abstracts data traces from sensors and simulations"
    DTDFVocab:provides AggregatedDataInsight
]

instance DashboardService : DTDFVocab:Service [
    base:desc "Provides real‑time visualization dashboard"
    DTDFVocab:provides DashboardVisualizationInsight
]

instance ComparativeAnalysisService : DTDFVocab:Service [
    base:desc "Compares simulated and measured torque/velocity to inform control updates"
    DTDFVocab:provides PerformanceOptimizationInsight, MaintenanceDecisionSupportInsight
]

// Insights
instance FrictionParameterUpdatedInsight : DTDFVocab:Insight [
    base:desc "Friction model parameters are updated and logged"
]

instance ControlAlgorithmTuningInsight : DTDFVocab:Insight [
    base:desc "Control algorithms can be tuned based on DT insights"
]

instance MaintenanceDecisionSupportInsight : DTDFVocab:Insight [
    base:desc "Decision support for maintenance (e.g., wear detection)"
]

instance PerformanceOptimizationInsight : DTDFVocab:Insight [
    base:desc "Performance optimization and wear detection insights"
]

instance SimulationResultsInsight : DTDFVocab:Insight [
    base:desc "Results from motor and gearbox simulation in Simulink"
]

instance AggregatedDataInsight : DTDFVocab:Insight [
    base:desc "Aggregated data traces of current, torque, and velocity"
]

instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real-Time visualization of system state in dashboard"
]

// Actions
instance TuneControlAlgorithmAction : DTDFVocab:Action [
    base:desc "Adjust control algorithm parameters based on updated friction parameters"
    DTDFVocab:IsAutomatic true
]

instance RecommendMaintenanceAction : DTDFVocab:Action [
    base:desc "Recommend maintenance procedure based on wear detection"
    DTDFVocab:IsAutomatic false
]

// Physical component
instance VerticalAxisFirst : DTDFVocab:Component [
    base:desc "First vertical axis of the MABI MAX100 industrial robot, comprising a permanent magnet synchronous motor, two gearboxes (gearwheel and cycloidal), and encoders"
]

// Environment containing the component
instance RobotVerticalAxisEnvironment : DTDFVocab:Environment [
    base:contains VerticalAxisFirst
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time streaming and continuous updating: sensor data is received at the sampling rate of the robot (typically several kHz for motor current, tens of Hz for encoder positions) and processed immediately; friction model updates occur online during operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "An orchestrated set comprising the physical asset (robot), its engineering model, the AAS, sensor data streams via MQTT, the processing component executing data‑calculation and simulation models, and a visualization dashboard; all components are linked via the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Design – structural SysML model of the first axis; manufacturing – acquisition of sensor data and default motor/gear parameters from the manufacturer; operation – live data streaming, continuous model refinement and friction identification; validation – comparison between simulated and measured data and updating of control parameters."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Fidelity achieved through embedding physics‑based white‑box models alongside black‑box models trained on measured data; validity is ensured by traceability of each data trace to its source and by continuous comparison of simulated results with measured torque and velocity; uncertainties arise from sensor noise and model parameter variations."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol is used for streaming sensor data from the robot to the digital shadow; Asset Administration Shells act as structural interfaces; no explicit mention of additional protocols such as OPC UA."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Modeling follows SysML and Asset Administration Shell (AAS) standards; MBSE practices (RFLP, OOSEM) are referenced; simulation uses Simulink following MATLAB engineering standards."
]
